SELECT citation_number
FROM citations
WHERE violation_code = '1';

SELECT COUNT(*) AS unpaid_fines_count
  FROM fines
 WHERE status = 'unpaid';

SELECT officer_id, COUNT(citation_id) AS total_citations
FROM citations
GROUP BY officer_id;

SELECT violation_description
FROM citations
WHERE citation_id = 0;

SELECT violation_name
FROM violations
WHERE violation_code = '1';

SELECT COUNT(citation_id) AS total_citations
  FROM citations
  WHERE officer_id = (SELECT officer_id FROM officers WHERE officer_name = 'Officer Jane Doe');
